#include <opencv2/opencv.hpp>

cv::Mat image = cv::imread("input.png");
if (image.empty())
{
    return -1;
}

cv::imshow("Preview", image);
cv::waitKey(0);

cv::Mat gray;
cv::Mat binary;
cv::cvtColor(image, gray, cv::COLOR_BGR2GRAY);
cv::threshold(gray, binary, 120, 255, cv::THRESH_BINARY);

cv::Mat gray;
cv::Mat edges;
cv::cvtColor(image, gray, cv::COLOR_BGR2GRAY);
cv::GaussianBlur(gray, gray, cv::Size(5, 5), 1.5);
cv::Canny(gray, edges, 80, 160);

int targetW = 640;
int targetH = 640;
double scale = std::min(targetW / static_cast<double>(image.cols), targetH / static_cast<double>(image.rows));
cv::Mat resized;
cv::resize(image, resized, cv::Size(), scale, scale);
cv::Mat canvas(targetH, targetW, image.type(), cv::Scalar(114, 114, 114));
resized.copyTo(canvas(cv::Rect(0, 0, resized.cols, resized.rows)));

std::vector<cv::Point2f> srcPts{{0, 0}, {300, 0}, {300, 200}, {0, 200}};
std::vector<cv::Point2f> dstPts{{0, 0}, {400, 0}, {400, 250}, {0, 250}};
cv::Mat H = cv::getPerspectiveTransform(srcPts, dstPts);
cv::Mat warped;
cv::warpPerspective(image, warped, H, cv::Size(400, 250));

static void OnMouse(int event, int x, int y, int flags, void *userData)
{
    if (event == cv::EVENT_LBUTTONDOWN)
    {
        std::cout << x << "," << y << std::endl;
    }
}

cv::namedWindow("Preview");
cv::setMouseCallback("Preview", OnMouse, nullptr);

class RoiPicker
{
public:
    static void MouseThunk(int event, int x, int y, int flags, void *userData)
    {
        auto *self = static_cast<RoiPicker *>(userData);
        if (self)
        {
            self->OnMouse(event, x, y, flags);
        }
    }

    void OnMouse(int event, int x, int y, int flags);
};

RoiPicker picker;
cv::namedWindow("Preview");
cv::setMouseCallback("Preview", &RoiPicker::MouseThunk, &picker);

class ThresholdController
{
public:
    int value = 120;

    static void OnTrackbar(int position, void *userData)
    {
        auto *self = static_cast<ThresholdController *>(userData);
        if (self)
        {
            self->value = position;
        }
    }
};

ThresholdController controller;
cv::createTrackbar("Threshold", "Controls", nullptr, 255, &ThresholdController::OnTrackbar, &controller);
cv::setTrackbarPos("Threshold", "Controls", controller.value);

cv::VideoCapture cap(0);
if (!cap.isOpened())
{
    return -1;
}

cv::Mat frame;
while (cap.read(frame))
{
    cv::imshow("Camera", frame);
    if (cv::waitKey(1) == 27)
    {
        break;
    }
}

auto subtractor = cv::createBackgroundSubtractorMOG2();
cv::Mat mask;
subtractor->apply(frame, mask);
cv::threshold(mask, mask, 200, 255, cv::THRESH_BINARY);

cv::KalmanFilter kf(4, 2);
kf.transitionMatrix = (cv::Mat_<float>(4, 4) << 1,0,1,0, 0,1,0,1, 0,0,1,0, 0,0,0,1);
setIdentity(kf.measurementMatrix);
setIdentity(kf.processNoiseCov, cv::Scalar::all(1e-4));
setIdentity(kf.measurementNoiseCov, cv::Scalar::all(1e-2));
setIdentity(kf.errorCovPost, cv::Scalar::all(1));

cv::Mat prediction = kf.predict();
cv::Mat measurement = (cv::Mat_<float>(2, 1) << x, y);
kf.correct(measurement);

auto orb = cv::ORB::create();
std::vector<cv::KeyPoint> keypoints;
cv::Mat descriptors;
orb->detectAndCompute(image, cv::noArray(), keypoints, descriptors);

std::vector<std::vector<cv::Point3f>> objectPoints;
std::vector<std::vector<cv::Point2f>> imagePoints;
cv::Size imageSize(1280, 720);
cv::Mat cameraMatrix;
cv::Mat distCoeffs;
std::vector<cv::Mat> rvecs;
std::vector<cv::Mat> tvecs;

double rms = cv::calibrateCamera(objectPoints, imagePoints, imageSize, cameraMatrix, distCoeffs, rvecs, tvecs);
std::cout << "RMS=" << rms << std::endl;

cv::Mat blob = cv::dnn::blobFromImage(image, 1.0 / 255.0, cv::Size(320, 320), cv::Scalar(), true, false);
net.setInput(blob);
cv::Mat output = net.forward();

/*
cv::imread(..., cv::IMREAD_COLOR) returns a BGR image.
Convert explicitly with cv::cvtColor when another component expects RGB:
    cv::cvtColor(imageBgr, imageRgb, cv::COLOR_BGR2RGB);
*/

/*
Modern OpenCV:
  cv::aruco::ArucoDetector detector(dictionary, detectorParameters);
  detector.detectMarkers(image, corners, ids, rejected);

Legacy cv::aruco::detectMarkers(...) remains documented as deprecated.
*/

cv::Mat score;
cv::matchTemplate(scene, templ, score, cv::TM_CCOEFF_NORMED);
double minVal = 0.0;
double maxVal = 0.0;
cv::Point minLoc;
cv::Point maxLoc;
cv::minMaxLoc(score, &minVal, &maxVal, &minLoc, &maxLoc);
cv::rectangle(scene, cv::Rect(maxLoc.x, maxLoc.y, templ.cols, templ.rows), cv::Scalar(0, 255, 0), 2);

cv::VideoCapture cap(0);
if (!cap.isOpened())
{
    return -1;
}

cv::Mat frame;
while (cap.read(frame))
{
    cv::Point center(frame.cols / 2, frame.rows / 2);
    cv::drawMarker(frame, center, cv::Scalar(0, 255, 0), cv::MARKER_CROSS, 40, 2);
    cv::imshow("Camera", frame);
    if (cv::waitKey(1) == 27) break;
}

cv::Mat hsv;
cv::cvtColor(frame, hsv, cv::COLOR_BGR2HSV);
cv::Mat mask;
cv::inRange(hsv, cv::Scalar(35, 80, 80), cv::Scalar(85, 255, 255), mask);
cv::Moments m = cv::moments(mask, true);
if (m.m00 > 0.0)
{
    cv::Point center(static_cast<int>(m.m10 / m.m00), static_cast<int>(m.m01 / m.m00));
    cv::circle(frame, center, 8, cv::Scalar(0, 255, 0), -1);
}

double focalPixels = 820.0;
double knownWidthMeters = 0.065;
double pixelWidth = static_cast<double>(bbox.width);
double distance = (knownWidthMeters * focalPixels) / pixelWidth;

int errorX = targetCenter.x - frame.cols / 2;
if (std::abs(errorX) > 40)
{
    SendCommand(errorX < 0 ? "TURN_LEFT" : "TURN_RIGHT");
}
else
{
    SendCommand("FORWARD");
}

enum class RobotState { Search, Track, Act };
RobotState state = RobotState::Search;

switch (state)
{
    case RobotState::Search:
        if (targetFound) state = RobotState::Track;
        else SendCommand("SCAN");
        break;
    case RobotState::Track:
        if (!targetFound) state = RobotState::Search;
        else if (distance < 0.25) state = RobotState::Act;
        else SendCommand("FOLLOW");
        break;
    case RobotState::Act:
        SendCommand("CAPTURE");
        state = RobotState::Search;
        break;
}

cv::putText(frame, "FPS: " + std::to_string(fps), {10, 24}, cv::FONT_HERSHEY_SIMPLEX, 0.7, {0,255,0}, 2);
cv::putText(frame, targetFound ? "TARGET LOCKED" : "SEARCHING", {10, 52}, cv::FONT_HERSHEY_SIMPLEX, 0.7, targetFound ? cv::Scalar(0,255,0) : cv::Scalar(0,165,255), 2);
cv::rectangle(frame, {5, 5}, {260, 70}, cv::Scalar(40, 40, 40), 2);

double error = static_cast<double>(targetCenter.x - frame.cols / 2);
double steering = error / (frame.cols / 2.0);
if (std::abs(steering) < 0.08) steering = 0.0;
steering = std::clamp(steering, -1.0, 1.0);
SendSteering(steering);

